sql:
SELECT COUNT(film_work_id) AS film_count
FROM film_work_genres
WHERE genre_id = 1;

SELECT title, AVG(rating) AS average_rating
FROM film_works
GROUP BY title;

SELECT full_name
FROM people
ORDER BY birth_date ASC;

SELECT AVG(fw.rating) AS average_awarded_movie_rating
FROM film_works fw
JOIN award_winners aw ON fw.film_work_id = aw.film_work_id;

external_knowledge:
- 'film maestros' refers to film directors; 
- 'painted the silver screen' is a metaphor for directing films; 
- 'masterpieces' refers to films; 
- 'highest accolades' refers to the highest average ratings.

sql:
SELECT title
FROM film_works
WHERE rating = (SELECT MAX(rating) FROM film_works);

SELECT title
FROM film_works
ORDER BY runtime DESC;

SELECT title
FROM film_works
WHERE runtime > (SELECT AVG(runtime) FROM film_works);

SELECT title, rating
FROM film_works
ORDER BY rating DESC;
